// five-org/five-protocol/src/test_fixtures.rs
// Golden Fixtures for Parser/Verifier Coverage Tests
//
// This module provides runtime-generated bytecode samples that exercise:
// - Valid headers and instructions
// - Invalid CALL targets (out-of-bounds function indices)
// - Operand truncation (incomplete fixed-size operand)
//
// These fixtures are built at runtime using BytecodeBuilder to avoid raw byte
// constants and ensure tests reflect the canonical builder behavior. They are
// exported behind the "test-fixtures" feature for use in integration tests
// (e.g., five-solana verifier alignment).

use crate::{BytecodeBuilder, JUMP};

/// Return a valid header bytecode with minimal content: header + HALT
pub fn valid_header() -> alloc::vec::Vec<u8> {
    let mut b = BytecodeBuilder::new();
    b.emit_header(1, 2);
    b.emit_halt();
    b.build()
}

/// Return invalid CALL target bytecode: CALL to address 200 (outside bytecode bounds)
pub fn invalid_call_target() -> alloc::vec::Vec<u8> {
    let mut b = BytecodeBuilder::new();
    b.emit_header(1, 2);
    b.emit_call(200, 0); // 3-byte call to out-of-bounds address
    b.build()
}

/// Return bytecode with truncated operand: JUMP opcode followed by 1 byte (expects 2)
pub fn operand_truncation() -> alloc::vec::Vec<u8> {
    let mut b = BytecodeBuilder::new();
    b.emit_header(1, 2);
    b.emit_opcode(JUMP);
    // Emit only 1 byte of the 2-byte JUMP offset
    b.emit_u8(0);
    b.build()
}
